// 1. Pegue o texto que o OpenRouter gerou. 
// ATENÇÃO: Mude o ".text" abaixo para o nome exato do campo que o seu nó do OpenRouter está retornando (pode ser .message ou .content)
let respostaIA = $input.item.json.text; 

// 2. Limpa qualquer formatação de markdown (crases) caso a IA seja teimosa
let textoLimpo = respostaIA.replace(/```json/gi, '').replace(/```/gi, '').trim();

// 3. Converte a string limpa em um objeto JSON real
let dadosConvertidos = JSON.parse(textoLimpo);

// 4. Retorna o objeto puro para o n8n
return dadosConvertidos.items;

// --- CONFIGURAÇÃO ---
const MAPA_NUTRIENTES = {
    calorias:     { number: "208", unit: "kcal" },
    proteinas:    { number: "203", unit: "g" },
    gorduras:     { number: "204", unit: "g" },
    carboidratos: { number: "205", unit: "g" }
};

// --- ENTRADA DE DADOS ---
const itemLoop = $('Loop Over Items').item.json;

const quantidadeInformada = Number(itemLoop.quantity_g) || 0;
const produtoNome = String(itemLoop.food_name_br || '').trim();

if (!produtoNome) {
    return { json: { erro: "Nome do produto não informado" } };
}

if (quantidadeInformada <= 0) {
    return { json: { erro: "Quantidade inválida (deve ser maior que 0)" } };
}

// Acessa a resposta da API USDA
const responseData = items[0].json;
const foods = responseData.foods || [];

if (!foods || foods.length === 0) {
    return { json: { erro: "Alimento não encontrado na base USDA" } };
}

// --- SELEÇÃO DO MELHOR ALIMENTO ---
function escolherMelhorAlimento(foodsList, nomeBuscado) {
    const nomeLower = nomeBuscado.toLowerCase();

    // Prioridade 1: descrição que contém o nome exato e não é produto processado
    let candidato = foodsList.find(food => {
        const desc = food.description.toLowerCase();
        return desc.includes(nomeLower) &&
               !desc.includes("product") &&
               !desc.includes("candy") &&
               !desc.includes("juice") &&
               !desc.includes("dried") &&
               !desc.includes("overripe") &&   // evita banana muito madura com mais açúcar
               !desc.includes("baby food");
    });

    // Prioridade 2: qualquer descrição que contenha o nome
    if (!candidato) {
        candidato = foodsList.find(food => 
            food.description.toLowerCase().includes(nomeLower)
        );
    }

    // Prioridade 3: pega o primeiro da lista
    return candidato || foodsList[0];
}

const alimentoSelecionado = escolherMelhorAlimento(foods, produtoNome);
const nutrientesDaAPI = alimentoSelecionado.foodNutrients || [];

console.log(`✅ Alimento selecionado: ${alimentoSelecionado.description}`);
console.log(`FDC ID: ${alimentoSelecionado.fdcId}`);

// --- FUNÇÃO PARA CALCULAR NUTRIENTE ---
function calcularMacro(numeroNutriente) {
    const nutriente = nutrientesDaAPI.find(n => n.nutrientNumber === numeroNutriente);

    if (!nutriente || nutriente.value == null || isNaN(nutriente.value)) {
        console.log(`⚠️ Nutriente ${numeroNutriente} não encontrado ou valor inválido`);
        return 0;
    }

    // A API retorna valor por 100g → proporcional à quantidade informada
    const valorCalculado = (nutriente.value / 100) * quantidadeInformada;
    return parseFloat(valorCalculado.toFixed(2));
}

// --- SAÍDA ---
return {
    json: {
        produto: produtoNome,
        descricao_usda: alimentoSelecionado.description,   // importante para debug
        quantidade_g: quantidadeInformada,
        calorias: calcularMacro(MAPA_NUTRIENTES.calorias.number),
        carboidratos: calcularMacro(MAPA_NUTRIENTES.carboidratos.number),
        proteinas: calcularMacro(MAPA_NUTRIENTES.proteinas.number),
        gorduras: calcularMacro(MAPA_NUTRIENTES.gorduras.number),
    }
};

const itensCalculados = $input.all();

let totais = { kcal: 0, carbo: 0, prot: 0, gord: 0 };
let listaTexto = "";

for (const item of itensCalculados) {
    const d = item.json;

    totais.kcal += Number(d.calorias || 0);
    totais.carbo += Number(d.carboidratos || 0);
    totais.prot += Number(d.proteinas || 0);
    totais.gord += Number(d.gorduras || 0);

    listaTexto += `🔸 *${d.produto}* (${d.quantidade_g}g) - ${d.calorias} kcal\n`;
}

let mensagem = `🍽️ *Resumo da sua Refeição!* 🍽️\n\n${listaTexto}`;
mensagem += `\n📊 *TOTAL:*\n`;
mensagem += `🔥 ${totais.kcal.toFixed(2)} kcal\n`;
mensagem += `🍞 ${totais.carbo.toFixed(2)}g carbo\n`;
mensagem += `🥩 ${totais.prot.toFixed(2)}g proteína\n`;
mensagem += `🥑 ${totais.gord.toFixed(2)}g gordura\n`;

return [
  {
    json: {
      mensagem_whatsapp: mensagem,
      itens: itensCalculados.map(i => i.json),
      totais
    }
  }
];
